) external auth lock isStopped(1) returns (uint256 id) {
    // Input validation
    require(tab  >          0, "Clipper/zero-tab");
    require(lot  >          0, "Clipper/zero-lot");
    require(usr != address(0), "Clipper/zero-usr");
    id = ++kicks;
    require(id   >          0, "Clipper/overflow");

    active.push(id);

    sales[id].pos = active.length - 1;

    sales[id].tab = tab;
    sales[id].lot = lot;
    sales[id].usr = usr;
    sales[id].tic = uint96(block.timestamp);

    uint256 top;
    top = rmul(getFeedPrice(), buf);
    require(top > 0, "Clipper/zero-top-price");
    sales[id].top = top;

    // incentive to kick auction
    uint256 _tip  = tip;
    uint256 _chip = chip;
    uint256 coin;
    if (_tip > 0 || _chip > 0) {
        coin = add(_tip, wmul(tab, _chip));
        vat.suck(vow, kpr, coin);
    }

    emit Kick(id, top, tab, lot, usr, kpr, coin);
}

function pow(UD60x18 x, UD60x18 y) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();
    uint256 yUint = y.unwrap();

    // If both x and y are zero, the result is `UNIT`. If just x is zero, the result is always zero.
    if (xUint == 0) {
        return yUint == 0 ? UNIT : ZERO;
    }
    // If x is `UNIT`, the result is always `UNIT`.
    else if (xUint == uUNIT) {
        return UNIT;
    }

    // If y is zero, the result is always `UNIT`.
    if (yUint == 0) {
        return UNIT;
    }
    // If y is `UNIT`, the result is always x.
    else if (yUint == uUNIT) {
        return x;
    }

    // If x is > UNIT, use the standard formula.
    if (xUint > uUNIT) {
        result = exp2(mul(log2(x), y));
    }
    // Conversely, if x < UNIT, use the equivalent formula.
    else {
        UD60x18 i = wrap(uUNIT_SQUARED / xUint);
        UD60x18 w = exp2(mul(log2(i), y));
        result = wrap(uUNIT_SQUARED / w.unwrap());
    }
}

function powu(SD59x18 x, uint256 y) pure returns (SD59x18 result) {
    if (y == 0) return UNIT;
    uint256 xAbs = uint256(abs(x).unwrap());

    // Calculate the first iteration of the loop in advance.
    uint256 resultAbs = y & 1 > 0 ? xAbs : uint256(uUNIT);

    // Equivalent to `for(y /= 2; y > 0; y /= 2)`.
    uint256 yAux = y;
    for (yAux >>= 1; yAux > 0; yAux >>= 1) {
        xAbs = Common.mulDiv18(xAbs, xAbs);

        // Equivalent to `y % 2 == 1`.
        if (yAux & 1 > 0) {
            resultAbs = Common.mulDiv18(resultAbs, xAbs);
        }
    }

    // The result must fit in SD59x18.
    if (resultAbs > uint256(uMAX_SD59x18)) {
        revert Errors.PRBMath_SD59x18_Powu_Overflow(x, y);
    }

    unchecked {
        // Is the base negative and the exponent odd? If yes, the result should be negative.
        int256 resultInt = int256(resultAbs);
        bool isNegative = x.unwrap() < 0 && y & 1 == 1;
        if (isNegative) {
            resultInt = -resultInt;
        }
        result = wrap(resultInt);
    }
}

function mint(
    address recipient,
    int24 tickLower,
    int24 tickUpper,
    uint128 amount,
    bytes calldata data
) external override lock returns (uint256 amount0, uint256 amount1) {
    require(amount > 0);
    (, int256 amount0Int, int256 amount1Int) =
        _modifyPosition(
            ModifyPositionParams({
                owner: recipient,
                tickLower: tickLower,
                tickUpper: tickUpper,
                liquidityDelta: int256(amount).toInt128()
            })
        );

    amount0 = uint256(amount0Int);
    amount1 = uint256(amount1Int);

    uint256 balance0Before;
    uint256 balance1Before;
    if (amount0 > 0) balance0Before = balance0();
    if (amount1 > 0) balance1Before = balance1();
    IUniswapV3MintCallback(msg.sender).uniswapV3MintCallback(amount0, amount1, data);
    if (amount0 > 0) require(balance0Before.add(amount0) <= balance0(), 'M0');
    if (amount1 > 0) require(balance1Before.add(amount1) <= balance1(), 'M1');

    emit Mint(msg.sender, recipient, tickLower, tickUpper, amount, amount0, amount1);
}

function _add(
    CMT storage treaple,
    uint256 rootNodeId_,
    bytes32 key_
) private returns (uint256) {
    Node storage rootNode = treaple.nodes[uint64(rootNodeId_)];

    if (rootNode.key == 0) {
        return _newNode(treaple, key_);
    }

    if (rootNode.key == key_) revert KeyAlreadyExists();

    if (rootNode.key > key_) {
        rootNode.childLeft = uint64(_add(treaple, rootNode.childLeft, key_));

        if (treaple.nodes[rootNode.childLeft].priority > rootNode.priority) {
            rootNodeId_ = _rightRotate(treaple, rootNodeId_);
            rootNode = treaple.nodes[uint64(rootNodeId_)];
        }
    } else {
        rootNode.childRight = uint64(_add(treaple, rootNode.childRight, key_));

        if (treaple.nodes[rootNode.childRight].priority > rootNode.priority) {
            rootNodeId_ = _leftRotate(treaple, rootNodeId_);
            rootNode = treaple.nodes[uint64(rootNodeId_)];
        }
    }

    rootNode.merkleHash = _hashNodes(treaple, rootNodeId_);

    return rootNodeId_;
}

function flattenThree(
    MemoryPointer array1,
    MemoryPointer array2,
    MemoryPointer array3
) internal view returns (MemoryPointer newArray) {
    unchecked {
        uint256 arrayLength1 = array1.readUint256();
        uint256 arrayLength2 = array2.readUint256();
        uint256 arrayLength3 = array3.readUint256();
        uint256 array1HeadSize = arrayLength1 * 32;
        uint256 array2HeadSize = arrayLength2 * 32;
        uint256 array3HeadSize = arrayLength3 * 32;

        newArray = malloc(
            array1HeadSize + array2HeadSize + array3HeadSize + 32
        );
        newArray.write(arrayLength1 + arrayLength2 + arrayLength3);

        MemoryPointer dst = newArray.next();
        if (arrayLength1 > 0) {
            array1.next().copy(dst, array1HeadSize);
        }
        if (arrayLength2 > 0) {
            array2.next().copy(dst.offset(array1HeadSize), array2HeadSize);
        }
        if (arrayLength3 > 0) {
            array3.next().copy(
                dst.offset(array1HeadSize + array2HeadSize),
                array3HeadSize
            );
        }
    }
}

function _executeMultiplexBatchSellTokenForTokenCall(
    ExecuteState memory state
) private returns (bytes memory returnResult) {
    IERC20Token inputToken;
    IERC20Token outputToken;
    IMultiplexFeature.BatchSellSubcall[] memory calls;
    uint256 sellAmount;
    uint256 minBuyAmount;

    bytes memory args = _extractArgumentsFromCallData(state.mtx.callData);
    (inputToken, outputToken, calls, sellAmount, minBuyAmount) = abi.decode(
        args,
        (IERC20Token, IERC20Token, IMultiplexFeature.BatchSellSubcall[], uint256, uint256)
    );

    return
        _callSelf(
            state.hash,
            abi.encodeWithSelector(
                IMultiplexFeature._multiplexBatchSell.selector,
                IMultiplexFeature.BatchSellParams({
                    inputToken: inputToken,
                    outputToken: outputToken,
                    sellAmount: sellAmount,
                    calls: calls,
                    useSelfBalance: false,
                    recipient: state.mtx.signer,
                    payer: state.mtx.signer
                }),
                minBuyAmount
            )
        );
}

function swapMulti(
    IERC20[] memory tokens,
    uint256 amount,
    uint256 minReturn,
    uint256[] memory distribution,
    uint256[] memory flags
) public payable returns(uint256 returnAmount) {
    tokens[0].universalTransferFrom(msg.sender, address(this), amount);

    returnAmount = tokens[0].universalBalanceOf(address(this));
    for (uint i = 1; i < tokens.length; i++) {
        if (tokens[i - 1] == tokens[i]) {
            continue;
        }

        uint256[] memory dist = new uint256[](distribution.length);
        for (uint j = 0; j < distribution.length; j++) {
            dist[j] = (distribution[j] >> (8 * (i - 1))) & 0xFF;
        }

        _swap(
            tokens[i - 1],
            tokens[i],
            returnAmount,
            dist,
            flags[i - 1]
        );
        returnAmount = tokens[i].universalBalanceOf(address(this));
        tokens[i - 1].universalTransfer(msg.sender, tokens[i - 1].universalBalanceOf(address(this)));
    }

    require(returnAmount >= minReturn, "OneSplit: actual return amount is less than minReturn");
    tokens[tokens.length - 1].universalTransfer(msg.sender, returnAmount);
}

function _calculateUniswapWrapped(
    IERC20 fromToken,
    IERC20 midToken,
    IERC20 destToken,
    uint256 amount,
    uint256 parts,
    uint256 midTokenPrice,
    uint256 flags,
    uint256 gas1,
    uint256 gas2
) internal view returns(uint256[] memory rets, uint256 gas) {
    if (!fromToken.isETH() && destToken.isETH()) {
        (rets, gas) = _calculateUniswap(
            midToken,
            destToken,
            _linearInterpolation(amount.mul(1e18).div(midTokenPrice), parts),
            flags
        );
        return (rets, gas + gas1);
    }
    else if (fromToken.isETH() && !destToken.isETH()) {
        (rets, gas) = _calculateUniswap(
            fromToken,
            midToken,
            _linearInterpolation(amount, parts),
            flags
        );

        for (uint i = 0; i < parts; i++) {
            rets[i] = rets[i].mul(midTokenPrice).div(1e18);
        }
        return (rets, gas + gas2);
    }

    return (new uint256[](parts), 0);
}

function decRelay(bytes memory raw) internal pure returns (Relay memory m) {
    Pb.Buffer memory buf = Pb.fromBytes(raw);

    uint256 tag;
    Pb.WireType wire;
    while (buf.hasMore()) {
        (tag, wire) = buf.decKey();
        if (false) {}
        // solidity has no switch/case
        else if (tag == 1) {
            m.sender = Pb._address(buf.decBytes());
        } else if (tag == 2) {
            m.receiver = Pb._address(buf.decBytes());
        } else if (tag == 3) {
            m.token = Pb._address(buf.decBytes());
        } else if (tag == 4) {
            m.amount = Pb._uint256(buf.decBytes());
        } else if (tag == 5) {
            m.srcChainId = uint64(buf.decVarint());
        } else if (tag == 6) {
            m.dstChainId = uint64(buf.decVarint());
        } else if (tag == 7) {
            m.srcTransferId = Pb._bytes32(buf.decBytes());
        } else {
            buf.skipValue(wire);
        } // skip value of unknown tag
    }
}

function harvest(uint256 _vaultId) external expectInitialized returns (uint256, uint256) {

  Vault.Data storage _vault = _vaults.get(_vaultId);

  (uint256 _harvestedAmount, uint256 _decreasedValue) = _vault.harvest(address(this));

  if (_harvestedAmount > 0) {
    uint256 _feeAmount = _harvestedAmount.mul(harvestFee).div(PERCENT_RESOLUTION);
    uint256 _distributeAmount = _harvestedAmount.sub(_feeAmount);

    FixedPointMath.FixedDecimal memory _weight = FixedPointMath.fromU256(_distributeAmount).div(totalDeposited);
    _ctx.accumulatedYieldWeight = _ctx.accumulatedYieldWeight.add(_weight);

    if (_feeAmount > 0) {
      token.safeTransfer(rewards, _feeAmount);
    }

    if (_distributeAmount > 0) {
      _distributeToTransmuter(_distributeAmount);

      // token.safeTransfer(transmuter, _distributeAmount); previous version call
    }
  }

  emit FundsHarvested(_harvestedAmount, _decreasedValue);

  return (_harvestedAmount, _decreasedValue);
}

function _recoverGroup(
  bytes32 hash,
  bytes memory signatures
) internal pure returns (address[] memory signers) {
  // Ensure that the signatures length is a multiple of 65.
  if (signatures.length % 65 != 0) {
    return new address[](0);
  }

  // Create an appropriately-sized array of addresses for each signer.
  signers = new address[](signatures.length / 65);

  // Get each signature location and divide into r, s and v variables.
  bytes32 signatureLocation;
  bytes32 r;
  bytes32 s;
  uint8 v;

  for (uint256 i = 0; i < signers.length; i++) {
    assembly {
      signatureLocation := add(signatures, mul(i, 65))
      r := mload(add(signatureLocation, 32))
      s := mload(add(signatureLocation, 64))
      v := byte(0, mload(add(signatureLocation, 96)))
    }

    // EIP-2 still allows signature malleability for ecrecover(). Remove
    // this possibility and make the signature unique.
    if (uint256(s) > 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF5D576E7357A4501DDFE92F46681B20A0) {
      continue;
    }

    if (v != 27 && v != 28) {
      continue;
    }

    // If signature is valid & not malleable, add signer address.
    signers[i] = ecrecover(hash, v, r, s);
  }
}

function _parseTransactionInput(
    bytes calldata data_,
    uint256 offset_
) private pure returns (TransactionInput memory input_, uint256 consumed_) {
    uint256 position_ = offset_;

    _checkForBufferOverflow(position_ + 32, data_.length);

    input_.previousHash = (bytes32(data_.slice(position_, position_ + 32))).bytes32LEtoBE();

    position_ += 32;

    _checkForBufferOverflow(position_ + 4, data_.length);

    input_.previousIndex = uint32(bytes4(data_[position_:position_ + 4])).uint32LEtoBE();

    position_ += 4;

    uint256 scriptLen_;
    uint256 lenSize_;

    (scriptLen_, lenSize_) = _parseCuint(data_, position_);

    position_ += lenSize_;

    _checkForBufferOverflow(position_ + scriptLen_, data_.length);

    input_.script = data_.slice(position_, position_ + scriptLen_);

    position_ += scriptLen_;

    _checkForBufferOverflow(position_ + 4, data_.length);

    input_.sequence = uint32(bytes4(data_[position_:position_ + 4])).uint32LEtoBE();

    position_ += 4;

    consumed_ = position_ - offset_;
}

function _twiceAffine(
    call512 call_,
    uint512 p_,
    uint512 two_,
    uint512 three_,
    uint512 a_,
    uint512 x1_,
    uint512 y1_
) private view returns (uint512 x2_, uint512 y2_) {
    unchecked {
        if (U512.isNull(x1_)) {
            return (x2_, y2_);
        }

        if (U512.eqU256(y1_, 0)) {
            return (x2_, y2_);
        }

        uint512 m1_ = U512.modexpU256(call_, x1_, 2, p_);
        U512.modmulAssign(call_, m1_, three_, p_);
        U512.redaddAssign(call_, m1_, a_, p_);

        uint512 m2_ = U512.modmul(call_, y1_, two_, p_);
        U512.moddivAssign(call_, m1_, m2_, p_);

        x2_ = U512.modexpU256(call_, m1_, 2, p_);
        U512.redsubAssign(call_, x2_, x1_, p_);
        U512.redsubAssign(call_, x2_, x1_, p_);

        y2_ = U512.redsub(call_, x1_, x2_, p_);
        U512.modmulAssign(call_, y2_, m1_, p_);
        U512.redsubAssign(call_, y2_, y1_, p_);
    }
}

function settle() external isNotForceStop phaseSettlement preventReentrant {
    _settle();

    (uint256 poolBase, uint256 poolQuote, uint256 poolI, uint256 unUsedBase, uint256 unUsedQuote) = getSettleResult();
    _UNUSED_BASE_ = unUsedBase;
    _UNUSED_QUOTE_ = unUsedQuote;

    address _poolBaseToken;
    address _poolQuoteToken;

    if (_UNUSED_BASE_ > poolBase) {
        _poolBaseToken = address(_QUOTE_TOKEN_);
        _poolQuoteToken = address(_BASE_TOKEN_);
    } else {
        _poolBaseToken = address(_BASE_TOKEN_);
        _poolQuoteToken = address(_QUOTE_TOKEN_);
    }

    _POOL_ = IDVMFactory(_POOL_FACTORY_).createDODOVendingMachine(
        _poolBaseToken,
        _poolQuoteToken,
        _POOL_FEE_RATE_,
        poolI,
        DecimalMath.ONE,
        _IS_OPEN_TWAP_
    );

    uint256 avgPrice = unUsedBase == 0 ? _I_ : DecimalMath.divCeil(poolQuote, unUsedBase);
    _AVG_SETTLED_PRICE_ = avgPrice;

    _transferBaseOut(_POOL_, poolBase);
    _transferQuoteOut(_POOL_, poolQuote);

    (_TOTAL_LP_AMOUNT_, ,) = IDVM(_POOL_).buyShares(address(this));

    msg.sender.transfer(_SETTEL_FUND_);

    emit Settle();
}

function getCPInfoByUser(address pool, address user) external view returns (bool isHaveCap, int curQuota, uint256 userFee) {
    CPPoolInfo memory cpPoolInfo = cpPools[pool];
    if(cpPoolInfo.quoteToken == address(0)) {
        isHaveCap = false;
        curQuota = -1;
        userFee = 0;
    }else {
        address quotaAddr = cpPoolInfo.quotaAddr;
        curQuota = cpPoolInfo.globalQuota;
        if(quotaAddr != address(0))
            curQuota = IQuota(quotaAddr).getUserQuota(user);

        if(curQuota == -1) {
            isHaveCap = false;
        }else {
            isHaveCap = true;
            uint256 userStake = ICrowdPooling(pool).getShares(user);
            if(uint256(curQuota) >= userStake) {
                curQuota = int(uint256(curQuota).sub(userStake));
            }else {
                curQuota = 0;
            }
        }

        address feeAddr = cpPoolInfo.feeAddr;
        if(feeAddr == address(0)) {
            userFee =  0;
        } else {
            userFee = IFee(feeAddr).getUserFee(user);
        }
    }
}

function permit(
    address owner,
    address spender,
    uint256 value,
    uint256 deadline,
    uint8 v,
    bytes32 r,
    bytes32 s
) external {
    require(deadline >= block.timestamp, "DODO_GSP_LP: EXPIRED");
    bytes32 digest =
        keccak256(
            abi.encodePacked(
                "\x19\x01",
                DOMAIN_SEPARATOR,
                keccak256(
                    abi.encode(
                        PERMIT_TYPEHASH,
                        owner,
                        spender,
                        value,
                        nonces[owner]++,
                        deadline
                    )
                )
            )
        );

    address recoveredAddress = ecrecover(digest, v, r, s);
    require(
        recoveredAddress != address(0) && recoveredAddress == owner,
        "DODO_GSP_LP: INVALID_SIGNATURE"
    );
    _approve(owner, spender, value);
}

function interfaceImplementer(
    bytes32 node,
    bytes4 interfaceID
) external view virtual override returns (address) {
    address implementer = versionable_interfaces[recordVersions[node]][
        node
    ][interfaceID];
    if (implementer != address(0)) {
        return implementer;
    }

    address a = addr(node);
    if (a == address(0)) {
        return address(0);
    }

    (bool success, bytes memory returnData) = a.staticcall(
        abi.encodeWithSignature(
            "supportsInterface(bytes4)",
            type(IERC165).interfaceId
        )
    );
    if (!success || returnData.length < 32 || returnData[31] == 0) {
        // EIP 165 not supported by target
        return address(0);
    }

    (success, returnData) = a.staticcall(
        abi.encodeWithSignature("supportsInterface(bytes4)", interfaceID)
    );
    if (!success || returnData.length < 32 || returnData[31] == 0) {
        // Specified interface not supported by target
        return address(0);
    }

    return a;
}

function parseNamespace(
    bytes memory name,
    uint256 offset
) internal pure returns (bool valid, uint256 coinType) {
    (bytes32 labelHash, uint256 offsetTLD) = NameCoder.readLabel(
        name,
        offset
    );
    if (labelHash == keccak256(bytes(SLUG_ETH))) {
        coinType = COIN_TYPE_ETH;
    } else if (labelHash == keccak256(bytes(SLUG_DEFAULT))) {
        coinType = COIN_TYPE_DEFAULT;
    } else if (labelHash == bytes32(0)) {
        return (false, 0); // no slug
    } else {
        (bytes32 word, bool validHex) = HexUtils.hexStringToBytes32(
            name,
            1 + offset,
            offsetTLD
        );
        if (!validHex) return (false, 0); // invalid coinType or too long
        coinType = uint256(word);
    }
    (labelHash, offset) = NameCoder.readLabel(name, offsetTLD);
    if (labelHash != keccak256(bytes(TLD_REVERSE))) return (false, 0); // invalid tld
    (labelHash, ) = NameCoder.readLabel(name, offset);
    if (labelHash != bytes32(0)) return (false, 0); // not tld
    valid = true;
}

function getProof(bytes key) public view returns (uint branchMask, bytes32[] _siblings) {
    require(tree.root != 0);
    Data.Label memory k = Data.Label(keccak256(key), 256);
    Data.Edge memory e = tree.rootEdge;
    bytes32[256] memory siblings;
    uint length;
    uint numSiblings;
    while (true) {
        var (prefix, suffix) = k.splitCommonPrefix(e.label);
        assert(prefix.length == e.label.length);
        if (suffix.length == 0) {
            // Found it
            break;
        }
        length += prefix.length;
        branchMask |= uint(1) << 255 - length;
        length += 1;
        var (head, tail) = suffix.chopFirstBit();
        siblings[numSiblings++] = tree.nodes[e.node].children[1 - head].edgeHash();
        e = tree.nodes[e.node].children[head];
        k = tail;
    }
    if (numSiblings > 0) {
        _siblings = new bytes32[](numSiblings);
        for (uint i = 0; i < numSiblings; i++) {
            _siblings[i] = siblings[i];
        }
    }
}

function _follow(
    uint256 followerProfileId,
    address transactionExecutor,
    uint256 idOfProfileToFollow,
    uint256 followTokenId,
    bytes calldata followModuleData
) private returns (uint256) {
    Types.Profile storage _profileToFollow = StorageLib.getProfile(idOfProfileToFollow);

    address followNFT = _profileToFollow.followNFT;
    if (followNFT == address(0)) {
        followNFT = _deployFollowNFT(idOfProfileToFollow);
        _profileToFollow.followNFT = followNFT;
    }

    return
        _processFollow(
            ProcessFollowParams({
                followNFT: followNFT,
                followerProfileId: followerProfileId,
                transactionExecutor: transactionExecutor,
                idOfProfileToFollow: idOfProfileToFollow,
                followTokenId: followTokenId,
                followModule: _profileToFollow.followModule,
                followModuleData: followModuleData
            })
        );
}

function swapTokens(
    string calldata _aggregatorId,
    IERC20 _tokenFrom,
    IERC20 _tokenTo,
    address _recipient,
    uint256 _amountFrom,
    uint256 _balanceFromBefore,
    bytes calldata _swapData
)
    external
    onlySelf
{
    uint256 tokenFromObtained_ = _getSelfBalance(_tokenFrom) - _balanceFromBefore;
    if (tokenFromObtained_ < _amountFrom) revert InsufficientTokens();

    if (tokenFromObtained_ > _amountFrom) {
        _sendTokens(_tokenFrom, tokenFromObtained_ - _amountFrom, _recipient);
    }

    uint256 balanceToBefore_ = _getSelfBalance(_tokenTo);

    uint256 value_ = 0;

    if (address(_tokenFrom) == address(0)) {
        value_ = _amountFrom;
    } else {
        uint256 allowance_ = _tokenFrom.allowance(address(this), address(metaSwap));
        if (allowance_ < _amountFrom) {
            _tokenFrom.safeIncreaseAllowance(address(metaSwap), type(uint256).max);
        }
    }

    metaSwap.swap{ value: value_ }(_aggregatorId, _tokenFrom, _amountFrom, _swapData);

    uint256 obtainedAmount_ = _getSelfBalance(_tokenTo) - balanceToBefore_;

    _sendTokens(_tokenTo, obtainedAmount_, _recipient);
}

function provideLiquidity(address tokenToUse, uint256 amount, uint256 MFIMin) public override onlyTreasury {

    IPancakeRouter02 pancakeRouter = IPancakeRouter02(contractRegistry.getContractAddress(PANCAKE_ROUTER_HASH));
    IERC20 MFI = IERC20(contractRegistry.getContractAddress(MFI_HASH));
    IERC20 liquidityToken = IERC20(tokenToUse);

    uint256 mfiTokens = MFI.balanceOf(address(this));

    liquidityToken.approve(address(pancakeRouter), amount);
    MFI.approve(address(pancakeRouter), mfiTokens);

    (uint256 MFIProvided, uint256 liquidityTokensProvided, uint256 newLPTokenAmount) = pancakeRouter.addLiquidity(
        address(MFI),
        tokenToUse,
        mfiTokens,
        amount,
        MFIMin,
        amount,
        msg.sender,
        block.timestamp
    );

    if (MFI.balanceOf(address(this)) > 0) {
        MFI.safeTransfer(msg.sender, MFI.balanceOf(address(this)));
    }

    if (liquidityToken.balanceOf(address(this)) > 0) {
        liquidityToken.safeTransfer(msg.sender, liquidityToken.balanceOf(address(this)));
    }

    emit LiquidityProvided(tokenToUse, MFIProvided, liquidityTokensProvided, newLPTokenAmount);
}

function _stopTrackingToken(TokenType tokenType, address token, string calldata liquidityControllerName) internal {

    if (tokenType == TokenType.RESERVE_TOKEN) {
        for (uint256 x = 0; x < reserveTokens.length; x++) {
            if (reserveTokens[x] == token) {
                reserveTokens[x] = reserveTokens[reserveTokens.length - 1];
                reserveTokens.pop();
                break;
            }
        }
    } else if (tokenType == TokenType.LIQUIDITY_TOKEN) {
        for (uint256 x = 0; x < liquidityTokens.length; x++) {
            if (liquidityTokens[x] == token) {
                liquidityTokens[x] = liquidityTokens[liquidityTokens.length - 1];
                liquidityTokens.pop();
                break;
            }
        }
    } else if (tokenType == TokenType.LP_TOKEN) {
        for (uint256 x = 0; x < lpTokens.length; x++) {
            if (lpTokens[x].baseToken == token && keccak256(abi.encodePacked(lpTokens[x].liquidityController)) == keccak256(abi.encodePacked(liquidityControllerName))) {
                lpTokens[x] = lpTokens[lpTokens.length - 1];
                lpTokens.pop();
                break;
            }
        }
    }

}

function _startTrackingToken(TokenType tokenType, address token, bool isReserveToken, string calldata liquidityControllerName) internal {

    if (tokenType == TokenType.RESERVE_TOKEN) {

        for (uint256 x = 0; x < reserveTokens.length; x++) {
            if (reserveTokens[x] == token) return;
        }

        reserveTokens.push(token);
    } else if (tokenType == TokenType.LIQUIDITY_TOKEN) {

        for (uint256 x = 0; x < liquidityTokens.length; x++) {
            if (liquidityTokens[x] == token) return;
        }

        liquidityTokens.push(token);
    } else if (tokenType == TokenType.LP_TOKEN) {

        for (uint256 x = 0; x < lpTokens.length; x++) {
            if (lpTokens[x].baseToken == token) return;
        }

        if (!isReserveToken) {
            require(contractRegistry.getPriceCalculator(token) != address(0), "no price calculator");
        }

        lpTokens.push(LPTokenSettings(liquidityControllerName, token, isReserveToken));
    }
}

function _handleListingAndFindersFees(
    uint256 _remainingProfit,
    StoredAuction storage auction,
    address currency
) internal returns (uint256 remainingProfit) {
    remainingProfit = _remainingProfit;
    uint256 listingFee;
    address listingFeeRecipient;
    uint256 findersFee;
    address finder;

    if (_hasFeature(auction.features, FEATURE_MASK_LISTING_FEE)) {
        uint16 listingFeeBps;
        (listingFeeBps, listingFeeRecipient) = _getListingFee(auction);
        listingFee = (remainingProfit * listingFeeBps) / 10000;
    }

    if (_hasFeature(auction.features, FEATURE_MASK_FINDERS_FEE)) {
        uint16 findersFeeBps;
        (findersFeeBps, finder) = _getFindersFee(auction);
        if (finder != address(0)) {
            findersFee = (remainingProfit * findersFeeBps) / 10000;
        }
    }

    if (listingFee > 0) {
        _handleOutgoingTransfer(listingFeeRecipient, listingFee, currency, 50000);
        remainingProfit -= listingFee;
    }

    if (findersFee > 0) {
        _handleOutgoingTransfer(finder, findersFee, currency, 50000);
        remainingProfit -= findersFee;
    }
}

function withdraw(
    uint256 assets,
    address receiver,
    bytes memory adaptorData,
    bytes memory configData
) public override {
    // Run external receiver check.
    _externalReceiverCheck(receiver);

    // Withdraw assets from Aave.
    IAaveToken token = IAaveToken(abi.decode(adaptorData, (address)));
    pool.withdraw(token.UNDERLYING_ASSET_ADDRESS(), assets, address(this));

    (, uint256 totalDebtETH, , , , uint256 healthFactor) = pool.getUserAccountData(address(this));
    if (totalDebtETH > 0) {
        // Run minimum health factor checks.
        uint256 minHealthFactor = abi.decode(configData, (uint256));
        if (minHealthFactor == 0) {
            revert BaseAdaptor__UserWithdrawsNotAllowed();
        }
        // Check if adaptor minimum health factor is more conservative than strategist set.
        if (minHealthFactor < minimumHealthFactor) minHealthFactor = minimumHealthFactor;
        if (healthFactor < minHealthFactor) revert AaveATokenAdaptor__HealthFactorTooLow();
    }

    // Transfer assets to receiver.
    ERC20(token.UNDERLYING_ASSET_ADDRESS()).safeTransfer(receiver, assets);
}

function distributeERC20(address currency, uint256 amount) external {
    uint256 length = _beneficiaries.length;
    uint256 totalDistribution;

    bool callerIsBeneficiary;
    for (uint256 i; i < length; ) {
        if (_beneficiaries[i] == _msgSender()) {
            callerIsBeneficiary = true;
            break;
        }
        unchecked {
            ++i;
        }
    }
    if (!callerIsBeneficiary) revert OnlyBeneficiary();

    for (uint256 i; i < length; ) {
        uint256 share;
        address beneficiary = _beneficiaries[i];
        if (i == length - 1) {
            share = amount - totalDistribution; // leftover to last beneficiary
        } else {
            share = (amount * _sharesBps[beneficiary]) / MAX_BPS;
        }
        IERC20(currency).transfer(beneficiary, share);

        unchecked {
            totalDistribution += share;
            ++i;
        }
    }

    emit ERCPaymentDistributed(_msgSender(), currency, amount);
}
